CYPHER 25
// Step 1: collect community IDs that contain at least one known fraudster
MATCH (fraudster:Customer {fraudFlag: true})
WHERE fraudster.louvainCommunity IS NOT NULL
WITH collect(DISTINCT fraudster.louvainCommunity) AS fraudCommunities

// Step 2: find non-fraudulent customers in those same communities
MATCH (c:Customer)
WHERE c.louvainCommunity IN fraudCommunities
  AND NOT coalesce(c.fraudFlag, false)

// Step 3: batch-write the suspicion marker in small commits
CALL (c) {
  SET c.suspicionReason   = 'suspicious due to network association',
      c.suspicionUpdatedAt = datetime()
} IN TRANSACTIONS OF 500 ROWS
RETURN count(*) AS suspiciousCustomersMarked
